'use client';

import React, { createContext, useContext, useState } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import styles from './ui/Loader.module.css';

interface LoaderContextProps {
  startLoading: (callback: () => void) => void;
}

const LoaderContext = createContext<LoaderContextProps | undefined>(undefined);

export const useLoader = () => {
  const context = useContext(LoaderContext);
  if (!context) throw new Error("useLoader must be used within LoaderProvider");
  return context;
};

export function LoaderProvider({ children }: { children: React.ReactNode }) {
  const [isLoading, setIsLoading] = useState(false);

  const startLoading = (callback: () => void) => {
    setIsLoading(true);
    // Global 3 seconds wait time as requested
    setTimeout(() => {
      setIsLoading(false);
      callback();
    }, 3000);
  };

  return (
    <LoaderContext.Provider value={{ startLoading }}>
      {children}
      <AnimatePresence>
        {isLoading && (
          <motion.div 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className={styles.overlay}
          >
            <div className={styles.loader}>
              <div className={`${styles.box} ${styles.box1}`}></div>
              <div className={`${styles.box} ${styles.box2}`}></div>
              <div className={`${styles.box} ${styles.box3}`}></div>
              <div className={`${styles.box} ${styles.box4}`}></div>
              <div className={`${styles.box} ${styles.box5}`}></div>
              <div className={styles.logo}>
                {/* Minimalist 3D box wireframe representation for logo */}
                <svg viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                  <path d="M12 2L2 7l10 5 10-5-10-5z" />
                  <path d="M2 17l10 5 10-5" />
                  <path d="M2 12l10 5 10-5" />
                </svg>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </LoaderContext.Provider>
  );
}
